import React, { createContext, useState, useContext } from 'react';

const TemaContext = createContext();

export const useTema = () => {
  const context = useContext(TemaContext);
  if (!context) throw new Error('useTema debe usarse dentro de TemaProvider');
  return context;
};

export const TemaProvider = ({ children }) => {
  const [colorFondo, setColorFondo] = useState('oscuro');
  const [tamañoLetra, setTamañoLetra] = useState('medium');

  const colores = {
    oscuro: '#0a0a0a',
    claro: '#f0f4f8',
    azul: '#1a1a2e',
    gradient: 'linear-gradient(135deg, #0a0a0a 0%, #1a1a2e 100%)'
  };

  const tamaños = {
    pequeño: '12px',
    medium: '16px',
    grande: '20px',
    extragrande: '24px'
  };

  const cambiarColorFondo = (color) => setColorFondo(color);
  const cambiarTamañoLetra = (tamaño) => setTamañoLetra(tamaño);

  return (
    <TemaContext.Provider value={{ colorFondo, tamañoLetra, cambiarColorFondo, cambiarTamañoLetra, colores, tamaños }}>
      {children}
    </TemaContext.Provider>
  );
};
